sp_angular_provider.script:
function scmTableFilter(spUtil) {
    "use strict";

    function readSessionCache(key) {
        if (!key || typeof sessionStorage === "undefined") {
            return null;
        }

        try {
            var raw = sessionStorage.getItem(key);
            return raw ? JSON.parse(raw) : null;
        } catch (error) {
            return null;
        }
    }

    function writeSessionCache(key, value) {
        if (!key || typeof sessionStorage === "undefined") {
            return;
        }

        try {
            sessionStorage.setItem(key, JSON.stringify(value));
        } catch (error) {
            // Best effort only.
        }
    }

    function getChoiceValuesSessionKey(tableProviderScriptInclude, fieldName) {
        /* prettier-ignore */
        return ("scmTable.choiceValues::" + String(tableProviderScriptInclude || "") + "::" + String(fieldName || ""));
    }

    function getReferenceDisplaySessionKey(tableName, sysId) {
        /* prettier-ignore */
        return ("scmTable.referenceDisplay::" + String(tableName || "") + "::" + String(sysId || ""));
    }

    function normalizeLogicalOperator(logicalOperator) {
        return String(logicalOperator || "and").toLowerCase() === "or"
            ? "or"
            : "and";
    }

    function createEmptyFilterCondition() {
        return {
            id: spUtil.createUid("xxxx-xxxx"),
            field: "",
            label: "",
            type: "",
            logicalOperator: "and",
            operator: "",
            value: "",
            valueTo: "",
            choiceValues: [],
            loading: false,
        };
    }

    function getDefaultOperatorForType(type) {
        if (type === "date") {
            return "on";
        }

        if (type === "string") {
            return "contains";
        }

        return "is";
    }

    function requiresConditionValue(condition) {
        if (!condition || !condition.field || !condition.operator) {
            return false;
        }

        return !["is_empty", "is_not_empty", "is_anything"].includes(
            condition.operator,
        );
    }

    function buildFilterFieldMap(filterFields) {
        var map = {};

        (filterFields || []).forEach(function (fieldConfig) {
            if (!fieldConfig || !fieldConfig.field) {
                return;
            }

            map[fieldConfig.field] = angular.copy(fieldConfig);
        });

        return map;
    }

    function populateConditionFromField(condition, fieldConfig, options) {
        options = options || {};
        var loadChoiceValues = options.loadChoiceValues;

        if (!fieldConfig) {
            condition.label = "";
            condition.type = "";
            condition.operator = "";
            condition.value = "";
            condition.valueTo = "";
            condition.displayValue = "";
            condition.choiceValues = [];
            condition.loading = false;
            condition.referenceTable = undefined;
            condition.referenceSearchField = undefined;
            condition.displayField = undefined;
            condition.searchFields = undefined;
            condition.placeholder = undefined;
            condition.referenceQualifier = undefined;
            condition.pageSize = undefined;
            condition.minimumInputLength = 3;
            condition.displayFields = undefined;
            condition.orderBy = undefined;
            condition.orderDirection = undefined;
            return;
        }

        condition.label = fieldConfig.label || "";
        condition.type = fieldConfig.type || "string";
        condition.operator = getDefaultOperatorForType(condition.type);
        condition.value = "";
        condition.valueTo = "";
        condition.displayValue = "";

        condition.referenceTable = fieldConfig.referenceTable;
        condition.referenceSearchField = fieldConfig.referenceSearchField;
        condition.displayField = fieldConfig.displayField;
        condition.searchFields =
            fieldConfig.searchFields ||
            fieldConfig.referenceSearchField ||
            fieldConfig.displayField ||
            "";
        condition.placeholder =
            fieldConfig.placeholder ||
            (fieldConfig.label ? "Search " + fieldConfig.label : "Search");
        condition.referenceQualifier = fieldConfig.referenceQualifier;
        condition.pageSize = fieldConfig.pageSize;
        condition.minimumInputLength = fieldConfig.minimumInputLength || 3;
        condition.displayFields =
            fieldConfig.displayFields || fieldConfig.displayField || "";
        condition.orderBy = fieldConfig.orderBy;
        condition.orderDirection = fieldConfig.orderDirection;

        if (condition.type === "choice") {
            if (typeof loadChoiceValues === "function") {
                loadChoiceValues(condition);
            }
            return;
        }

        condition.choiceValues = [];
        condition.loading = false;
    }

    function restoreFilterConditionsFromApplied(options) {
        options = options || {};

        var appliedFilters = options.appliedFilters || [];
        var filterFieldMap = options.filterFieldMap || {};
        var createEmpty =
            options.createEmptyFilterCondition || createEmptyFilterCondition;
        var populate = options.populateConditionFromField;

        var filterConditions = [];

        appliedFilters.forEach(function (appliedFilter) {
            var condition = createEmpty();
            condition.field = appliedFilter.field;

            if (typeof populate === "function") {
                populate(
                    condition,
                    filterFieldMap[appliedFilter.field] || null,
                );
            }

            condition.operator = appliedFilter.operator || condition.operator;
            condition.logicalOperator = normalizeLogicalOperator(
                appliedFilter.logicalOperator,
            );
            condition.value = appliedFilter.value || "";
            condition.valueTo = appliedFilter.valueTo || "";
            condition.displayValue = appliedFilter.displayValue || "";
            condition.source = appliedFilter.source || "";

            filterConditions.push(condition);
        });

        return filterConditions.length ? filterConditions : [createEmpty()];
    }

    function buildDialogFilters(filters) {
        if (!Array.isArray(filters)) {
            return [];
        }

        return filters
            .filter(function (filter) {
                if (!filter || !filter.field) {
                    return false;
                }

                if (!requiresConditionValue(filter)) {
                    return true;
                }

                return filter.value != null && String(filter.value) !== "";
            })
            .map(function (filter) {
                return {
                    field: filter.field,
                    label: filter.label,
                    type: filter.type,
                    logicalOperator: normalizeLogicalOperator(
                        filter.logicalOperator,
                    ),
                    value: filter.value,
                    valueTo: filter.valueTo,
                    operator: filter.operator,
                    choiceValues: filter.choiceValues,
                    referenceTable: filter.referenceTable,
                    referenceSearchField: filter.referenceSearchField,
                    displayField: filter.displayField,
                    searchFields: filter.searchFields,
                    displayFields: filter.displayFields,
                    referenceQualifier: filter.referenceQualifier,
                    displayValue: filter.displayValue,
                    source: filter.source,
                    id: filter.id,
                };
            });
    }

    function getAppliedFiltersForRequests(appliedFilters) {
        return Array.isArray(appliedFilters) ? appliedFilters : [];
    }

    function addFilterCondition(filters, afterIndex, logicalOperator) {
        var nextFilters = Array.isArray(filters)
            ? filters.slice()
            : [createEmptyFilterCondition()];

        var nextCondition = createEmptyFilterCondition();

        if (
            Number.isInteger(afterIndex) &&
            afterIndex >= 0 &&
            afterIndex < nextFilters.length
        ) {
            // Assign logicalOperator to the filter at afterIndex (the one being connected FROM)
            nextFilters[afterIndex].logicalOperator =
                normalizeLogicalOperator(logicalOperator);
            // Add new condition after it
            nextFilters.splice(afterIndex + 1, 0, nextCondition);
        } else {
            nextFilters.push(nextCondition);
        }

        return nextFilters;
    }

    function removeFilterCondition(filters, conditionIndex) {
        if (!Array.isArray(filters)) {
            return [createEmptyFilterCondition()];
        }

        var nextFilters = filters.slice();
        nextFilters.splice(conditionIndex, 1);

        if (nextFilters.length === 0) {
            nextFilters.push(createEmptyFilterCondition());
        }

        return nextFilters;
    }

    function loadChoiceValues(options) {
        options = options || {};

        var server = options.server;
        var transactionId = options.transactionId;
        var tableProviderScriptInclude = options.tableProviderScriptInclude;
        var filter = options.filter;
        var choiceValuesCache = options.choiceValuesCache || {};
        var choiceValueRequestState = options.choiceValueRequestState || {};
        /* prettier-ignore */
        var requestKey = String(transactionId || "") + "::" + String(tableProviderScriptInclude || "") + "::" + String((filter && filter.field) || "");
        var requestId = (choiceValueRequestState[requestKey] || 0) + 1;
        choiceValueRequestState[requestKey] = requestId;

        if (!filter || !filter.field || !server) {
            return Promise.resolve();
        }

        if (choiceValuesCache[filter.field]) {
            filter.choiceValues = angular.copy(choiceValuesCache[filter.field]);
            filter.loading = false;
            return Promise.resolve(filter.choiceValues);
        }

        var sessionChoiceValues = readSessionCache(
            getChoiceValuesSessionKey(tableProviderScriptInclude, filter.field),
        );

        if (Array.isArray(sessionChoiceValues) && sessionChoiceValues.length) {
            choiceValuesCache[filter.field] = angular.copy(sessionChoiceValues);
            filter.choiceValues = angular.copy(sessionChoiceValues);
            filter.loading = false;
            return Promise.resolve(filter.choiceValues);
        }

        filter.loading = true;
        return server
            .get({
                action: "getChoiceValues",
                transactionId: transactionId,
                tableProviderScriptInclude: tableProviderScriptInclude,
                fieldName: filter.field,
            })
            .then(function (response) {
                if (choiceValueRequestState[requestKey] !== requestId) {
                    return [];
                }

                filter.choiceValues = response.data.choiceValues || [];
                choiceValuesCache[filter.field] = angular.copy(
                    filter.choiceValues,
                );
                writeSessionCache(
                    getChoiceValuesSessionKey(
                        tableProviderScriptInclude,
                        filter.field,
                    ),
                    filter.choiceValues,
                );
                filter.loading = false;
                return filter.choiceValues;
            })
            .catch(function () {
                if (choiceValueRequestState[requestKey] !== requestId) {
                    return [];
                }

                filter.loading = false;
                return [];
            });
    }

    function resolveReferenceFilterDisplayValues(options) {
        options = options || {};

        var server = options.server;
        var transactionId = options.transactionId;
        var tableProviderScriptInclude = options.tableProviderScriptInclude;
        var filters = options.filters || [];
        var referenceDisplayCache = options.referenceDisplayCache || {};

        if (!server) {
            return Promise.resolve();
        }

        var referenceFilters = (filters || []).filter(function (filter) {
            return (
                filter &&
                filter.type === "reference" &&
                filter.referenceTable &&
                filter.value
            );
        });

        var pendingLookups = {};

        var requests = referenceFilters.map(function (filter) {
            /* prettier-ignore */
            var cacheKey = String(filter.referenceTable || "") + "::" + String(filter.value || "");

            if (filter.displayValue) {
                referenceDisplayCache[cacheKey] = filter.displayValue;
                writeSessionCache(
                    getReferenceDisplaySessionKey(
                        filter.referenceTable,
                        filter.value,
                    ),
                    filter.displayValue,
                );
                return Promise.resolve();
            }

            if (referenceDisplayCache[cacheKey]) {
                filter.displayValue = referenceDisplayCache[cacheKey];
                return Promise.resolve();
            }

            var cachedDisplayValue = readSessionCache(
                getReferenceDisplaySessionKey(
                    filter.referenceTable,
                    filter.value,
                ),
            );

            if (typeof cachedDisplayValue === "string" && cachedDisplayValue) {
                referenceDisplayCache[cacheKey] = cachedDisplayValue;
                filter.displayValue = cachedDisplayValue;
                return Promise.resolve();
            }

            if (!pendingLookups[cacheKey]) {
                pendingLookups[cacheKey] = server
                    .get({
                        action: "getReferenceDisplayValue",
                        transactionId: transactionId,
                        tableProviderScriptInclude: tableProviderScriptInclude,
                        table: filter.referenceTable,
                        sysId: filter.value,
                    })
                    .then(function (response) {
                        var resolvedDisplayValue =
                            response.data.displayValue || filter.value || "";
                        referenceDisplayCache[cacheKey] = resolvedDisplayValue;
                        writeSessionCache(
                            getReferenceDisplaySessionKey(
                                filter.referenceTable,
                                filter.value,
                            ),
                            resolvedDisplayValue,
                        );
                        return resolvedDisplayValue;
                    })
                    .catch(function () {
                        var fallbackValue = filter.value || "";
                        referenceDisplayCache[cacheKey] = fallbackValue;
                        return fallbackValue;
                    });
            }

            return pendingLookups[cacheKey].then(function (displayValue) {
                filter.displayValue = displayValue;
            });
        });

        return Promise.all(requests);
    }

    return {
        createEmptyFilterCondition: createEmptyFilterCondition,
        getDefaultOperatorForType: getDefaultOperatorForType,
        requiresConditionValue: requiresConditionValue,
        buildFilterFieldMap: buildFilterFieldMap,
        populateConditionFromField: populateConditionFromField,
        restoreFilterConditionsFromApplied: restoreFilterConditionsFromApplied,
        buildDialogFilters: buildDialogFilters,
        getAppliedFiltersForRequests: getAppliedFiltersForRequests,
        addFilterCondition: addFilterCondition,
        removeFilterCondition: removeFilterCondition,
        loadChoiceValues: loadChoiceValues,
        resolveReferenceFilterDisplayValues:
            resolveReferenceFilterDisplayValues,
    };
}
